  const ayahs: AyahProps[] = [
    { ayahId: 34, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: true, textData: "تُرْجَعُونَؐ" },
    { ayahId: 35, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "هُوَ ۰ﻟ﮲ خَلَقَ لَكُم مَّا فِى ۱لاَرْضِ جَمِيعاًؐ ثُمَّ \"سْتَوۭيٰٓ إِلَي ۰لسَّمَآءِ فَسَوّۭيٰهُنَّ سَبْعَ سَمَــٰوَ؛تٍؐ وَهُوَ بِكُلِّ شَيْءٖ عَلِيمٌؐ" },
    { ayahId: 36, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "وَإِذْ قَالَ رَبُّكَ لِلْمَلَئِكَةِ إِنِّـﻰ جَاعِلٌ فِى ۱لاَرْضِ خَلِيفَةًؐ قَالُوٓاْ أَتَجْعَلُ فِيهَا مَنْ يُّفْسِدُ فِيهَا وَيَسْفِكُ ۴لدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَؐ قَالَ إِنِّيَ أَعْلَمُ مَا لاَ تَعْلَمُونَؐ" },
    { ayahId: 37, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "وَعَلَّمَ ءَادَمَ ۰لاَسْمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَي ۰لْمَلَئِكَةِ فَقَالَ أَنۢبِـُٔونِـى بِأَسْمَآءِ هَـٰٓؤُلٓاَءِ ان كُنتُمْ صَـٰدِقِينَؐ" },
    { ayahId: 38, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "قَالُواْ سُبْحَــٰنَكَ لاَ عِلْمَ لَنَآ إِلاَّ مَا عَلَّمْتَنَآ إِنَّكَ أَنتَ ۰لْعَلِيمُ ۴لْحَكِيمُؐ" },
    { ayahId: 39, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "قَالَ يَـٰٓــَٔادَمُ أَنۢبِـيؔهُم بِأَسْمَآئِهِمْؐ فَلَمَّآ أَنۢبَأَهُم بِأَسْمَآئِهِمْ قَالَ أَلَمَ اَقُل لَّكُمُ; إِنِّيَ أَعْلَمُ غَيْــبَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضِ وَأَعْلَمُ مَا تُبْدُونَ وَمَا كُنتُمْ تَكْتُمُونَؐ ®" },
    { ayahId: 40, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "وَإِذْ قُلْنَا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيسَ أَبۭيٰ وَاسْتَكْبَرَ وَكَانَ مِنَ ۰لْكۭـٰفِرۣينَؐ" },
    { ayahId: 41, surahNumber: 2, pageNumber: 6, isComplete: true, continuesFromPrev: false, textData: "وَقُلْنَا يَـٰٓــَٔادَمُ ۶سْكُنَ اَنــتَ وَزَوْجُكَ ۰لْجَنَّةَ وَكُلاَ مِنْهَا رَغَداٗ حَيْــثُ ﺷِﻴْٔـﺘُـمَاؐ وَلاَ تَقْرَبَا هَـٰذِهِ ۱لشَّجَرَةَ فَتَكُونَا مِنَ ۰لظَّـٰلِمِينَؐ" },
    { ayahId: 42, surahNumber: 2, pageNumber: 6, isComplete: false, continuesFromPrev: false, textData: "فَأَزَلَّهُمَا ۰لشَّيْطَـٰنُ عَنْهَا فَأَخْرَجَهُمَا" }
  ];

